import {
  Component,
  Element,
  State,
  Prop,
  Method,
  Event,
  EventEmitter,
  h
} from '@stencil/core';
import {
  getHostAttributes,
  getSpreadableAttributes,
  setStyleAttribute
} from '@src/utils/kds-utils/attributes/attributeUtils';
import { registerAttributeObserver } from '@src/utils/kds-utils/registerObserver';

interface KdsLabelHostElement extends HTMLInputElement {
  nativeElement: HTMLLabelElement;
}

/**
 * Label is used to add an accessible name to [labelable elements](https://html.spec.whatwg.org/multipage/forms.html#category-label) like checkboxes, inputs, and most native form controls.
 *
 * > **Note:** `<kds-label />` is a [primitive web component](primitives/) that accepts all props listed below and any attributes prefixed with `inner-`.
 * `inner-*` attributes are stripped of their `inner-` prefix and placed onto the native `<label>` element.
 *
 */
@Component({
  tag: 'kds-label',
  styleUrl: 'kds-label.css',
  shadow: false
})
export class KdsLabel {
  @Element() hostEl: KdsLabelHostElement;

  /** Places label to left of input. */
  @Prop() readonly leftOfInput?: boolean = false;

  /** Sets the `for` attribute. */
  @Prop() readonly for?: string;

  /** Associates a field to a form element. */
  @Prop() readonly form?: string;

  /** Sets the font size. */
  @Prop() readonly size: 'l' | 'm' | 's' | 'xs' = 'm';

  /** Sets a class to the rendered `<label>`. */
  @Prop() readonly labelClass?: string;

  @State() hasField: boolean = false;
  @State() hasRadioOrCheckbox: boolean = false;
  @State() innerAttrs: any;

  /**
   * Emits when the component has been loaded. Event's `detail` contains a reference to the inner label element.
   */
  @Event() ready: EventEmitter;

  private observer: MutationObserver;
  private labelObserver: MutationObserver;

  private labelElement: HTMLLabelElement;
  private sizeOpts = ['l', 'm', 's', 'xs'];

  getValidSize(size: string) {
    return this.sizeOpts.includes(size) ? size : 'm';
  }

  componentWillLoad() {
    this.observer = registerAttributeObserver(this);
    this.labelObserver = new MutationObserver(() => {
      this.labelElement && this.checkChildren(this.labelElement);
    });

    this.innerAttrs = getHostAttributes(this.hostEl);

    this.checkChildren(this.hostEl);
  }

  checkChildren(parent: HTMLElement) {
    const children = Array.from(parent.children);
    let hasField = false;
    let hasRadioOrCheckbox = false;
    children.forEach((child) => {
      switch (child.tagName) {
        case 'KDS-INPUT':
          hasField = true;
          break;
        case 'KDS-SELECT':
          hasField = true;
          break;
        case 'KDS-TEXTAREA':
          hasField = true;
          break;
        case 'KDS-RADIO':
          hasRadioOrCheckbox = true;
          break;
        case 'KDS-CHECKBOX':
          hasRadioOrCheckbox = true;
          break;
        case 'KDS-TOGGLE':
          hasRadioOrCheckbox = true;
          break;
        default:
      }
    });
    this.hasField = hasField;
    this.hasRadioOrCheckbox = hasRadioOrCheckbox;
  }

  componentDidLoad() {
    this.observer.observe(this.hostEl, { attributes: true });
    this.labelObserver.observe(this.labelElement, {
      characterData: true,
      childList: true
    });
    this.ready.emit(this.labelElement);
    this.hostEl.nativeElement = this.labelElement;
  }

  disconnectedCallback() {
    this.observer && this.observer.disconnect();
  }

  /**
   * Returns the native `<label>` element used under the hood.
   */
  @Method()
  getNativeElement(): Promise<HTMLLabelElement> {
    return Promise.resolve(this.labelElement!);
  }

  render() {
    const validFontSize = this.getValidSize(this.size);

    return (
      <label
        {...getSpreadableAttributes(this.innerAttrs)}
        htmlFor={this.for}
        form={this.form}
        class={{
          [`kds-Label kds-Text--${validFontSize}`]: true,
          'kds-Label--leftOfInput': this.leftOfInput,
          'kds-Label--hasField': this.hasField,
          'kds-Label--hasRadioOrCheckbox': this.hasRadioOrCheckbox,
          [this.labelClass]: Boolean(this.labelClass)
        }}
        ref={(el: HTMLLabelElement) => {
          this.labelElement = el;
          setStyleAttribute(el, this.innerAttrs);
        }}
      >
        <slot />
      </label>
    );
  }
}
